"use client";
import { kycScheme } from "@/lib/validations";
import { zodResolver } from "@hookform/resolvers/zod";
import { useRouter } from "next/navigation";
import React, { useState } from "react";
import { useForm } from "react-hook-form";
import z from "zod";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "./ui/form";
import { Input } from "./ui/input";
import { Button } from "./ui/button";
import { RadioGroup, RadioGroupItem } from "./ui/radio-group";
import { cn } from "@/lib/utils";

const KycForm = () => {
  const form = useForm<z.infer<typeof kycScheme>>({
    resolver: zodResolver(kycScheme),
    defaultValues: {
      citizen: "Yes",
      reside: "",
      id: "",
    },
  });
  const onSubmit = async (values: z.infer<typeof kycScheme>) => {
    console.log(values);
    // const result = await addProducts(values);
  };
  const [selectedCitizen, setselectedCitizen] = useState("Yes");
  const [selectedReside, setselectedReside] = useState("Yes");
  console.log(selectedCitizen);
  console.log(selectedReside);

  return (
    <Form {...form}>
      <form
        onSubmit={form.handleSubmit(onSubmit)}
        className="bg-[#f7f5dc] shadow-md rounded px-8 pt-6 pb-8 mb-4"
        method="POST"
      >
        <FormField
          control={form.control}
          name="citizen"
          render={({ field }) => (
            <FormItem className="mb-4">
              <FormLabel>Are you a filipino citizen?</FormLabel>
              <FormControl>
                <RadioGroup
                  onValueChange={setselectedCitizen}
                  defaultValue={field.value}
                  className="flex flex-row"
                >
                  <FormLabel
                    htmlFor="citizen_yes"
                    className={cn(
                      selectedCitizen == "Yes" ? "active" : "inactive",
                      "w-full flex items-center gap-3 rounded-lg border-2 p-3 cursor-pointer"
                    )}
                  >
                    <FormItem>
                      <FormControl>
                        <RadioGroupItem value="Yes" id="citizen_yes" />
                      </FormControl>
                    </FormItem>
                    Yes
                  </FormLabel>
                  <FormLabel
                    htmlFor="citizen_no"
                    className={cn(
                      selectedCitizen == "No" ? "active" : "inactive",
                      "w-full flex items-center gap-3 rounded-lg border-2 p-3 cursor-pointer"
                    )}
                  >
                    <FormItem>
                      <FormControl>
                        <RadioGroupItem value="No" id="citizen_no" />
                      </FormControl>
                    </FormItem>
                    No
                  </FormLabel>
                </RadioGroup>
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        ></FormField>
        <FormField
          control={form.control}
          name="citizen"
          render={({ field }) => (
            <FormItem className="mb-4">
              <FormLabel>Do you currently reside in the Philippines?</FormLabel>
              <FormControl>
                <RadioGroup
                  onValueChange={setselectedReside}
                  defaultValue={field.value}
                  className="flex flex-row"
                >
                  <FormLabel
                    htmlFor="reside_yes"
                    className={cn(
                      selectedReside == "Yes" ? "active" : "inactive",
                      "w-full flex items-center gap-3 rounded-lg border-2 p-3 cursor-pointer"
                    )}
                  >
                    <FormItem>
                      <FormControl>
                        <RadioGroupItem value="Yes" id="reside_yes" />
                      </FormControl>
                    </FormItem>
                    Yes
                  </FormLabel>
                  <FormLabel
                    htmlFor="reside_no"
                    className={cn(
                      selectedReside == "No" ? "active" : "inactive",
                      "w-full flex items-center gap-3 rounded-lg border-2 p-3 cursor-pointer"
                    )}
                  >
                    <FormItem>
                      <FormControl>
                        <RadioGroupItem value="No" id="reside_no" />
                      </FormControl>
                    </FormItem>
                    No
                  </FormLabel>
                </RadioGroup>
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        ></FormField>

        <FormField
          control={form.control}
          name="id"
          render={({ field }) => (
            <FormItem className="mb-4">
              <FormLabel>ID</FormLabel>
              <FormControl>
                <Input placeholder="ID" {...field} />
              </FormControl>
              {/* <FormDescription></FormDescription> */}
              <FormMessage />
            </FormItem>
          )}
        ></FormField>
        <Button type="submit" className="cursor-pointer">
          Submit
        </Button>
      </form>
    </Form>
  );
};

export default KycForm;
